#include<bits/stdc++.h>
using namespace std;
string tenisk(int k,int n){
	stack<int> s;
	string ans;
	while(n){
		s.push(n%k);
		n/=k;
	}
	while(s.size()){
		if(s.top()>=10){
			ans+=char('A'+s.top()-10);
		}
		else ans+=char('0'+s.top());
		s.pop();
	}
	return ans;
}
int main(void){
	int x,y;
	cin>>x>>y;
	cout<<tenisk(y,x);
    return false;
}
